def parse_command(args_list):
    """Parse a list of argument strings into a command dict."""
    if not args_list:
        return {'command': 'help', 'args': []}
    return {'command': args_list[0], 'args': args_list[1:]}

def list_directory(path='.'):
    """List contents of a directory with details."""
    entries = []
    for name in os.listdir(path):
        full_path = os.path.join(path, name)
        is_dir = os.path.isdir(full_path)
        size = 0 if is_dir else os.path.getsize(full_path)
        ext = '' if is_dir else os.path.splitext(name)[1]
        entries.append({'name': name, 'size': size, 'is_dir': is_dir, 'extension': ext})
    return entries

def search_files(pattern, root_path='.'):
    """Search for files matching a pattern using threads."""
    results = []
    lock = threading.Lock()
    def search_dir(directory):
        for dirpath, dirnames, filenames in os.walk(directory):
            for fname in filenames:
                if fnmatch.fnmatch(fname, pattern):
                    with lock:
                        results.append(os.path.join(dirpath, fname))
    threads = []
    for fname in os.listdir(root_path):
        full = os.path.join(root_path, fname)
        if os.path.isfile(full) and fnmatch.fnmatch(fname, pattern):
            results.append(full)
        elif os.path.isdir(full):
            t = threading.Thread(target=search_dir, args=(full,))
            threads.append(t)
            t.start()
    for t in threads:
        t.join()
    return results

class FileManager:
    """File operations: copy, move, delete, and batch rename."""
    def copy_file(self, src, dst):
        try:
            shutil.copy2(src, dst)
            return f"Copied {src} to {dst}"
        except Exception as e:
            return f"Error copying: {e}"
    def move_file(self, src, dst):
        try:
            shutil.move(src, dst)
            return f"Moved {src} to {dst}"
        except Exception as e:
            return f"Error moving: {e}"
    def delete_file(self, path):
        try:
            os.remove(path)
            return f"Deleted {path}"
        except Exception as e:
            return f"Error deleting: {e}"
    def batch_rename(self, directory, old_ext, new_ext):
        renamed = []
        for name in os.listdir(directory):
            if name.endswith(old_ext):
                old_path = os.path.join(directory, name)
                new_name = name[:-len(old_ext)] + new_ext
                new_path = os.path.join(directory, new_name)
                os.rename(old_path, new_path)
                renamed.append((name, new_name))
        return renamed

class BookmarkManager:
    """Manage bookmarked directories and command history with shelve."""
    def __init__(self, db_path):
        self.db_path = db_path
    def add_bookmark(self, name, path):
        with shelve.open(self.db_path) as db:
            bookmarks = db.get('bookmarks', {})
            bookmarks[name] = path
            db['bookmarks'] = bookmarks
    def list_bookmarks(self):
        with shelve.open(self.db_path) as db:
            return dict(db.get('bookmarks', {}))
    def remove_bookmark(self, name):
        with shelve.open(self.db_path) as db:
            bookmarks = db.get('bookmarks', {})
            if name in bookmarks:
                del bookmarks[name]
                db['bookmarks'] = bookmarks
                return True
            return False
    def add_history(self, command_str):
        with shelve.open(self.db_path) as db:
            history = db.get('history', [])
            history.append(command_str)
            db['history'] = history
    def get_history(self):
        with shelve.open(self.db_path) as db:
            return list(db.get('history', []))

class DirectoryTree:
    """A tree representation of a directory hierarchy."""
    def __init__(self, name, path, is_dir=True):
        self.name = name
        self.path = path
        self.is_dir = is_dir
        self.children = []
    def build(self, max_depth=3, current_depth=0):
        if not self.is_dir or current_depth >= max_depth:
            return self
        try:
            for entry in os.listdir(self.path):
                full = os.path.join(self.path, entry)
                child = DirectoryTree(entry, full, os.path.isdir(full))
                child.build(max_depth, current_depth + 1)
                self.children.append(child)
        except PermissionError:
            pass
        return self
    def find(self, name):
        queue = deque([self])
        while queue:
            node = queue.popleft()
            if node.name == name:
                return node
            queue.extend(node.children)
        return None
    def get_path(self):
        return self.path
    def __repr__(self):
        kind = 'DIR' if self.is_dir else 'FILE'
        return f"DirectoryTree({kind}: {self.name}, {len(self.children)} children)"

